import { useState, useRef, useCallback, useMemo, useEffect } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import FullCalendar from "@fullcalendar/react";
import dayGridPlugin from "@fullcalendar/daygrid";
import interactionPlugin from "@fullcalendar/interaction";
import { format, subMonths, addDays, differenceInDays, parseISO, startOfMonth, isBefore, isAfter, addMonths } from "date-fns";
import {
  ArrowLeft, AlertTriangle, AlertCircle, Send, Copy, Trash2, ClipboardList,
  Calendar, Clock, SunMedium, EyeOff,
} from "lucide-react";
import { toast } from "sonner";

import { Button } from "@/shadcn/components/ui/button";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import HarmonyForm, { type FormSchema } from "@/components/forms/HarmonyForm";
import { HarmonyFullCalendar } from "@/components/ui/harmony-full-calendar";

import { WorkScheduleMonthList } from "@/features/work-schedule/components/WorkScheduleMonthList";
import { useMyWorkScheduleMonths } from "@/features/work-schedule/hooks/useWorkScheduleMonths";
import { useWorkScheduleMutations } from "@/features/work-schedule/hooks/useWorkScheduleMutations";

import { workScheduleService } from "@/api/workScheduleService";
import { publicHolidayService } from "@/api/publicHolidayService";
import { extraShiftService } from "@/api/extraShiftService";
import { normaliseHolidays } from "@/features/work-schedule/utils";
import { useLeavesListQuery } from "@/features/leave-management/hooks/leaveHooks";

import { MONTH_OPTIONS } from "@/features/work-schedule/constants";
import { WorkScheduleStatus, ShiftType, LeaveType, LeaveSize } from "@/types/enums";
import { getApiErrorMessage } from "@/api/app/apiError";
import { useAuth } from "@/shared/AuthContext";
import { PERMISSIONS } from "@/constants/permissions";
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';

import type { WorkScheduleMonthSummary, UpdateWorkDayPayload, CreateExtraShiftDTO } from "@/types/dto";
import type { WorkScheduleResponse } from "@/features/work-schedule/types";

/* ============================
   MODULE-LEVEL CONSTANTS
   ============================ */

const leaveFormSchema: FormSchema = {
  formKey: "my-schedule-leave-form",
  title: "Time Off Request",
  fields: [
    {
      name: "leaveType",
      label: "Leave Type",
      inputType: "select",
      required: true,
      options: [
        { label: "Planned", value: "0" },
        { label: "Unplanned", value: "1" },
      ],
    },
    {
      name: "leaveSize",
      label: "Leave Size",
      inputType: "select",
      required: true,
      options: [
        { label: "Full Day", value: "0" },
        { label: "First Half", value: "1" },
        { label: "Second Half", value: "2" },
      ],
    },
    {
      name: "reason",
      label: "Reason",
      inputType: "textarea",
      required: true,
    },
  ],
};

/* ============================
   COMPONENT
   ============================ */

export default function MyWorkSchedule() {
  const { user, hasPermission } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const queryClient = useQueryClient();

  const rawYear = searchParams.get("year");
  const rawMonth = searchParams.get("month");
  const isCalendarMode = !!(rawYear && rawMonth);

  const year = isCalendarMode ? parseInt(rawYear!, 10) : new Date().getFullYear();
  const month = isCalendarMode ? parseInt(rawMonth!, 10) : new Date().getMonth() + 1;

  /* ── LIST MODE DATA ── */
  const { data: months = [], isLoading: monthsLoading } = useMyWorkScheduleMonths();

  const handleRowClick = (row: WorkScheduleMonthSummary) => {
    navigate(`${ROUTES.MY_WORK_SCHEDULE}?year=${row.year}&month=${row.month}`);
  };

  /* ── CALENDAR MODE STATE ── */
  const [isExtraShiftSubmitting, setIsExtraShiftSubmitting] = useState(false);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [isImportWeekModalOpen, setIsImportWeekModalOpen] = useState(false);
  const [isClearModalOpen, setIsClearModalOpen] = useState(false);
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false);
  const [selectedLeaveDate, setSelectedLeaveDate] = useState<string | null>(null);
  const [isExtraShiftModalOpen, setIsExtraShiftModalOpen] = useState(false);
  const [selectedExtraShiftDate, setSelectedExtraShiftDate] = useState<string | null>(null);
  const [extraShiftReason, setExtraShiftReason] = useState("");
  const [extraShiftType, setExtraShiftType] = useState<ShiftType>(ShiftType.MorningShift);
  const [contextMenu, setContextMenu] = useState<{ x: number; y: number; date: string } | null>(null);

  const [importSourceYear, setImportSourceYear] = useState<number>(() => subMonths(new Date(), 1).getFullYear());
  const [importSourceMonth, setImportSourceMonth] = useState<number>(() => subMonths(new Date(), 1).getMonth() + 1);
  const [importWeekSourceDate, setImportWeekSourceDate] = useState<string>(() => format(subMonths(new Date(), 1), "yyyy-MM-dd"));
  const [importWeekTargetDate, setImportWeekTargetDate] = useState<string>(() => format(new Date(), "yyyy-MM-dd"));

  const importSourceCalendarRef = useRef<FullCalendar>(null);
  const importTargetCalendarRef = useRef<FullCalendar>(null);
  const leaveFormRef = useRef<HTMLFormElement>(null);

  /* ── CALENDAR MODE DATA ── */
  const startDate = format(new Date(year, month - 1, 1), "yyyy-MM-dd");
  const endDate = format(new Date(year, month, 0), "yyyy-MM-dd");

  const { data: schedule, isLoading: scheduleLoading, isError: scheduleError } = useQuery<WorkScheduleResponse>({
    queryKey: queryKeys.workSchedule.schedule(year, month, false),
    queryFn: () => workScheduleService.getWorkSchedule(year, month),
    enabled: isCalendarMode,
    retry: false,
  });

  const { data: allHolidays = [] } = useQuery({
    queryKey: queryKeys.publicHolidays.list(),
    queryFn: async () => normaliseHolidays(await publicHolidayService.getAll()),
    staleTime: 1000 * 60 * 60,
    enabled: isCalendarMode,
  });

  const { data: leavesData } = useLeavesListQuery({
    year,
    month,
    pageSize: 100,
  });

  const { data: extraShifts = [] } = useQuery({
    queryKey: queryKeys.extraShifts(year, month),
    queryFn: () => extraShiftService.getByRange(startDate, endDate),
    staleTime: 1000 * 60 * 5,
    enabled: isCalendarMode,
  });

  const holidays = useMemo(
    () =>
      allHolidays.filter((h) => {
        try { return parseISO(h.date).getFullYear() === year; }
        catch { return false; }
      }),
    [allHolidays, year],
  );

  /* ── MUTATIONS ── */
  const {
    updateMutation,
    submitMutation,
    importMutation,
    importWeekMutation,
    clearMutation,
    leaveMutation,
  } = useWorkScheduleMutations(year, month);

  /* ── DERIVED STATUS ── */
  const scheduleStatus = (schedule?.status as WorkScheduleStatus) ?? WorkScheduleStatus.Draft;
  const isScheduleLocked = scheduleStatus === WorkScheduleStatus.Approved;
  const isDraftOrRejected =
    scheduleStatus === WorkScheduleStatus.Draft || scheduleStatus === WorkScheduleStatus.Rejected;

  const hasPlanPast = hasPermission(PERMISSIONS.WorkSchedule.PlanPast);

  const canEditCurrentMonth = useMemo(() => {
    if (hasPlanPast) return true;
    const today = new Date();
    const currentMonthStart = startOfMonth(today);
    const nextMonthStart = startOfMonth(addMonths(today, 1));
    const viewedMonthStart = startOfMonth(new Date(year, month - 1, 1));
    return (
      !isBefore(viewedMonthStart, currentMonthStart) &&
      !isAfter(viewedMonthStart, nextMonthStart)
    );
  }, [year, month, hasPlanPast]);

  const canSubmit = scheduleStatus === WorkScheduleStatus.Draft && canEditCurrentMonth
    && hasPermission(PERMISSIONS.WorkSchedule.Submit);
  const canImport = isDraftOrRejected && canEditCurrentMonth;
  const canClear = isDraftOrRejected && canEditCurrentMonth;

  /* ── HANDLERS ── */
  const handleDayEdit = useCallback(
    async (payload: UpdateWorkDayPayload) => {
      return new Promise<void>((resolve, reject) => {
        updateMutation.mutate(payload, {
          onSuccess: () => resolve(),
          onError: (err) => reject(err),
        });
      });
    },
    [updateMutation],
  );

  const handleSubmitSchedule = () => {
    if (schedule?.id) {
      submitMutation.mutate(schedule.id, {
        onSuccess: () => {
          setIsSubmitModalOpen(false);
          toast.success("Schedule submitted for review.");
        },
      });
    }
  };

  const handleImportSubmit = () => {
    if (!schedule) return;
    importMutation.mutate(
      {
        sourceYear: importSourceYear,
        sourceMonth: importSourceMonth,
        targetYear: schedule.year,
        targetMonth: schedule.month,
      },
      {
        onSuccess: () => {
          setIsImportModalOpen(false);
          toast.success("Month data imported.");
        },
      },
    );
  };

  const handleImportWeekAction = () => {
    importWeekMutation.mutate({
      SourceStartDate: importWeekSourceDate,
      TargetStartDate: importWeekTargetDate,
    });
  };

  const handleClearSchedule = () => {
    if (!schedule?.id) return;
    clearMutation.mutate(schedule.id, {
      onSuccess: () => {
        setIsClearModalOpen(false);
        toast.success("Schedule cleared successfully.");
      },
    });
  };

  const handleLeaveSubmit = (formData: Record<string, unknown>) => {
    if (!user?.id || !selectedLeaveDate) return;
    leaveMutation.mutate(
      {
        userProfileId: user.id,
        leaveDate: selectedLeaveDate,
        leaveType: formData.leaveType as LeaveType | undefined,
        leaveSize: formData.leaveSize as LeaveSize | undefined,
        reason: formData.reason as string,
      },
      {
        onSuccess: () => {
          setIsLeaveModalOpen(false);
          setSelectedLeaveDate(null);
          toast.success("Leave request submitted.");
        },
      },
    );
  };

  const handleExtraShiftSubmit = async () => {
    if (!selectedExtraShiftDate || !extraShiftReason.trim() || !user?.id) return;
    setIsExtraShiftSubmitting(true);
    try {
      const payload: CreateExtraShiftDTO = {
        userProfileId: user.id,
        date: selectedExtraShiftDate,
        shiftType: extraShiftType,
        reason: extraShiftReason,
      };
      await extraShiftService.create(payload);
      queryClient.invalidateQueries({ queryKey: queryKeys.extraShifts(year, month) });
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.scheduleMonth(year, month) });
      setIsExtraShiftModalOpen(false);
      setSelectedExtraShiftDate(null);
      setExtraShiftReason("");
      setExtraShiftType(ShiftType.MorningShift);
      toast.success("Extra shift added to schedule.");
    } catch (err) {
      toast.error(getApiErrorMessage(err));
    } finally {
      setIsExtraShiftSubmitting(false);
    }
  };

  /* ── CONTEXT MENU DISMISS ── */
  useEffect(() => {
    const dismiss = () => setContextMenu(null);
    window.addEventListener("click", dismiss);
    return () => window.removeEventListener("click", dismiss);
  }, []);

  const selectCls =
    "w-full px-3.5 py-2.5 border border-border rounded-xl text-sm text-foreground bg-background focus:outline-none focus:ring-2 focus:ring-primary/30 focus:border-primary transition-all shadow-sm font-medium";

  /* ── TOOLBAR ACTIONS ── */
  const toolbarActions = isCalendarMode ? (
    <div className="flex flex-wrap items-center gap-2">
      {canImport && (
        <>
          <Button variant="secondary" size="sm" onClick={() => setIsImportModalOpen(true)}>
            <Copy size={14} />
            Import Month
          </Button>
          <Button variant="secondary" size="sm" onClick={() => setIsImportWeekModalOpen(true)}>
            <ClipboardList size={14} />
            Import Week
          </Button>
        </>
      )}
      {canClear && (
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setIsClearModalOpen(true)}
          className="text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/10"
        >
          <Trash2 size={14} />
          Reset
        </Button>
      )}
      {canSubmit && (
        <Button
          size="sm"
          onClick={() => setIsSubmitModalOpen(true)}
          className="shadow-lg shadow-indigo-500/20"
        >
          <Send size={14} />
          Submit Schedule
        </Button>
      )}
    </div>
  ) : null;

  /* ══════════════════════════════════════════════
     LIST MODE
     ══════════════════════════════════════════════ */
  if (!isCalendarMode) {
    const today = new Date();
    const curYear = today.getFullYear();
    const curMonth = today.getMonth() + 1;
    const next = addMonths(today, 1);
    const nextYear = next.getFullYear();
    const nextMonth = next.getMonth() + 1;

    const hasCurrent = months.some(m => m.year === curYear && m.month === curMonth);
    const hasNext    = months.some(m => m.year === nextYear && m.month === nextMonth);

    const planButtons = (monthsLoading || (hasCurrent && hasNext)) ? undefined : (
      <div className="flex items-center gap-2">
        {!hasCurrent && (
          <Button size="sm" onClick={() => navigate(`${ROUTES.MY_WORK_SCHEDULE}?year=${curYear}&month=${curMonth}`)}>
            <Calendar size={14} />
            Plan for {format(new Date(curYear, curMonth - 1, 1), "MMMM")}
          </Button>
        )}
        {!hasNext && (
          <Button size="sm" variant="outline" onClick={() => navigate(`${ROUTES.MY_WORK_SCHEDULE}?year=${nextYear}&month=${nextMonth}`)}>
            <Calendar size={14} />
            Plan for {format(new Date(nextYear, nextMonth - 1, 1), "MMMM")}
          </Button>
        )}
      </div>
    );

    return (
      <WorkScheduleMonthList
        months={months}
        loading={monthsLoading}
        onRowClick={handleRowClick}
        toolbarRight={planButtons}
      />
    );
  }

  /* ══════════════════════════════════════════════
     CALENDAR MODE
     ══════════════════════════════════════════════ */
  return (
    <div className="space-y-4">
      {/* Shared modal label styles */}
      <style>{`
        .ws-label {
          display: block;
          font-size: 10px;
          font-weight: 700;
          color: var(--color-muted-foreground);
          text-transform: uppercase;
          letter-spacing: 0.08em;
          margin-bottom: 6px;
        }
      `}</style>

      {/* Back button row */}
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate(ROUTES.MY_WORK_SCHEDULE)}>
          <ArrowLeft size={14} />
          Back to list
        </Button>
      </div>

      {/* Past month error banner */}
      {scheduleError && (
        <div className="p-4 bg-amber-50 dark:bg-amber-950/30 border border-amber-200/80 dark:border-amber-800/50 rounded-2xl flex items-start gap-3">
          <div className="w-7 h-7 bg-amber-100 dark:bg-amber-950/50 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
            <AlertCircle className="w-3.5 h-3.5 text-amber-600" />
          </div>
          <div>
            <p className="text-xs font-bold text-amber-800 dark:text-amber-400 uppercase tracking-wide">
              Schedule Unavailable
            </p>
            <p className="text-sm text-amber-700 dark:text-amber-300 mt-1 leading-relaxed font-medium">
              This schedule cannot be accessed. Past months are locked unless you have the Plan Past permission.
            </p>
          </div>
        </div>
      )}

      {/* Rejected notes banner */}
      {scheduleStatus === WorkScheduleStatus.Rejected && schedule?.reviewNotes && (
        <div className="p-4 bg-rose-50 dark:bg-rose-950/30 border border-rose-200/80 dark:border-rose-800/50 rounded-2xl flex items-start gap-3">
          <div className="w-7 h-7 bg-rose-100 dark:bg-rose-950/50 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
            <AlertTriangle className="w-3.5 h-3.5 text-rose-500" />
          </div>
          <div>
            <p className="text-xs font-bold text-rose-800 dark:text-rose-400 uppercase tracking-wide">
              Rejected by Admin
            </p>
            <p className="text-sm text-rose-700 dark:text-rose-300 mt-1 leading-relaxed font-medium">
              {schedule.reviewNotes}
            </p>
          </div>
        </div>
      )}

      {/* Calendar */}
      <HarmonyFullCalendar
        schedules={schedule ? [schedule] : []}
        publicHolidays={holidays}
        leaves={leavesData?.data}
        extraShifts={extraShifts}
        initialDate={new Date(year, month - 1, 1)}
        editable={!isScheduleLocked && canEditCurrentMonth}
        onDayEdit={handleDayEdit}
        toolbarActions={toolbarActions}
        isLoading={scheduleLoading}
        onDateContextMenu={(date, x, y) => {
          setContextMenu({ x, y, date });
        }}
        onDateChange={(date) => {
          navigate(
            `${ROUTES.MY_WORK_SCHEDULE}?year=${date.getFullYear()}&month=${date.getMonth() + 1}`,
            { replace: true }
          );
        }}
      />

      {/* ══════════════════════════════════════════
          MODALS
         ══════════════════════════════════════════ */}

      {/* ── SUBMIT (Employee) ── */}
      <HarmonyDialog
        open={isSubmitModalOpen}
        onOpenChange={setIsSubmitModalOpen}
        title="Submit Schedule"
        description={format(new Date(year, month - 1, 1), "MMMM yyyy")}
        size="md"
        onSubmit={handleSubmitSchedule}
        submitLabel="Submit Schedule"
        isSubmitting={submitMutation.isPending}
      >
        <div className="space-y-5">
          <p className="text-foreground text-sm leading-relaxed font-medium">
            Are you sure you want to submit this schedule for administrative review?
            This will finalize all changes for the selected period.
          </p>
          <div className="p-4 bg-amber-50 border border-amber-200/80 rounded-2xl flex items-start gap-3">
            <div className="w-6 h-6 bg-amber-100 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
              <AlertCircle className="w-3.5 h-3.5 text-amber-600" />
            </div>
            <p className="text-amber-800 text-sm font-medium leading-relaxed">
              Once submitted, the schedule becomes read-only until an admin approves or rejects it.
            </p>
          </div>
          {submitMutation.isError && (
            <div className="p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">
                {getApiErrorMessage(submitMutation.error)}
              </p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* ── IMPORT MONTH ── */}
      <HarmonyDialog
        open={isImportModalOpen}
        onOpenChange={setIsImportModalOpen}
        title="Import from Month"
        description={
          schedule
            ? `Target: ${format(new Date(schedule.year, schedule.month - 1, 1), "MMMM yyyy")}`
            : ""
        }
        size="md"
        onSubmit={handleImportSubmit}
        submitLabel="Import Pattern"
        isSubmitting={importMutation.isPending}
        submitDisabled={
          schedule != null &&
          importSourceYear === schedule.year &&
          importSourceMonth === schedule.month
        }
      >
        <div className="space-y-5">
          <p className="text-foreground text-sm font-medium leading-relaxed">
            Copy the day-of-week shift pattern from a previous month into{" "}
            <span className="font-bold text-foreground">
              {schedule
                ? format(new Date(schedule.year, schedule.month - 1, 1), "MMMM yyyy")
                : "this month"}
            </span>
            . Work descriptions will be cleared.
          </p>
          <div className="p-4 bg-primary/5 border border-primary/20 rounded-2xl flex items-start gap-3">
            <div className="w-6 h-6 bg-primary/20 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
              <AlertCircle className="w-3.5 h-3.5 text-primary" />
            </div>
            <p className="text-foreground text-sm font-medium leading-relaxed">
              The most common shift per weekday will be applied. Existing entries will be overwritten.
            </p>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="ws-label">Source Year</label>
              <select
                value={importSourceYear}
                onChange={(e) => setImportSourceYear(Number(e.target.value))}
                className={selectCls}
              >
                {[
                  new Date().getFullYear() - 2,
                  new Date().getFullYear() - 1,
                  new Date().getFullYear(),
                  new Date().getFullYear() + 1,
                  new Date().getFullYear() + 2,
                ].map((y) => (
                  <option key={y} value={y}>{y}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="ws-label">Source Month</label>
              <select
                value={importSourceMonth}
                onChange={(e) => setImportSourceMonth(Number(e.target.value))}
                className={selectCls}
              >
                {MONTH_OPTIONS.map((m) => (
                  <option key={m.value} value={m.value}>{m.label}</option>
                ))}
              </select>
            </div>
          </div>
          {schedule &&
            importSourceYear === schedule.year &&
            importSourceMonth === schedule.month && (
              <div className="p-3.5 bg-rose-50 border border-rose-200/80 rounded-xl">
                <p className="text-destructive text-sm font-medium">
                  Source and target month must be different.
                </p>
              </div>
            )}
          {importMutation.isError && (
            <div className="p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">
                {getApiErrorMessage(importMutation.error)}
              </p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* ── IMPORT WEEK ── */}
      <HarmonyDialog
        open={isImportWeekModalOpen}
        onOpenChange={setIsImportWeekModalOpen}
        title="Import Week Pattern"
        description="Copy shift arrangements between weeks"
        size="3xl"
        onSubmit={handleImportWeekAction}
        submitLabel="Confirm Import"
        isSubmitting={importWeekMutation.isPending}
        submitDisabled={importWeekMutation.isPending}
      >
        <div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Source Selection */}
            <div className="space-y-3.5">
              <div className="flex items-center justify-between">
                <label className="ws-label">Source Week</label>
                <div className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-primary/10 rounded-lg">
                  <div className="w-1.5 h-1.5 rounded-full bg-primary" />
                  <span className="text-[10px] font-bold text-primary uppercase tracking-wide">
                    Selecting From
                  </span>
                </div>
              </div>
              <div className="border border-border rounded-2xl overflow-hidden bg-muted/20 p-2 shadow-sm">
                <div className="import-calendar-mini">
                  <FullCalendar
                    ref={importSourceCalendarRef}
                    plugins={[dayGridPlugin, interactionPlugin]}
                    initialView="dayGridMonth"
                    headerToolbar={{ left: "prev", center: "title", right: "next" }}
                    height="auto"
                    contentHeight="auto"
                    initialDate={importWeekSourceDate}
                    dateClick={(info) => {
                      setImportWeekSourceDate(info.dateStr);
                      const nextWeek = format(addDays(parseISO(info.dateStr), 7), "yyyy-MM-dd");
                      setImportWeekTargetDate(nextWeek);
                      importTargetCalendarRef.current?.getApi().gotoDate(nextWeek);
                    }}
                    events={[
                      {
                        start: importWeekSourceDate,
                        display: "background",
                        backgroundColor: "var(--color-primary)",
                      },
                    ]}
                  />
                </div>
              </div>
              <div className="flex items-center justify-between px-1">
                <p className="text-xs text-muted-foreground font-medium">Pattern date</p>
                <p className="text-xs font-bold text-foreground">
                  {format(parseISO(importWeekSourceDate), "MMMM dd, yyyy")}
                </p>
              </div>
            </div>

            {/* Target Selection */}
            <div className="space-y-3.5">
              <div className="flex items-center justify-between">
                <label className="ws-label">Target Week</label>
                <div className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-emerald-50 rounded-lg">
                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                  <span className="text-[10px] font-bold text-emerald-600 uppercase tracking-wide">
                    Applying To
                  </span>
                </div>
              </div>
              <div className="border border-border rounded-2xl overflow-hidden bg-muted/20 p-2 shadow-sm">
                <div className="import-calendar-mini">
                  <FullCalendar
                    ref={importTargetCalendarRef}
                    plugins={[dayGridPlugin, interactionPlugin]}
                    initialView="dayGridMonth"
                    headerToolbar={{ left: "prev", center: "title", right: "next" }}
                    height="auto"
                    contentHeight="auto"
                    initialDate={importWeekTargetDate}
                    dayCellClassNames={(arg) => {
                      const diff = differenceInDays(arg.date, parseISO(importWeekSourceDate));
                      const isValid = diff > 0 && diff % 7 === 0;
                      return isValid ? "valid-target-day" : "invalid-target-day";
                    }}
                    dateClick={(info) => {
                      const diff = differenceInDays(info.date, parseISO(importWeekSourceDate));
                      if (diff > 0 && diff % 7 === 0) {
                        setImportWeekTargetDate(info.dateStr);
                      }
                    }}
                    events={[
                      {
                        start: importWeekTargetDate,
                        display: "background",
                        backgroundColor: "var(--color-primary)",
                      },
                    ]}
                  />
                </div>
              </div>
              <div className="flex items-center justify-between px-1">
                <p className="text-xs text-muted-foreground font-medium">Apply to week of</p>
                <p className="text-xs font-bold text-foreground">
                  {format(parseISO(importWeekTargetDate), "MMMM dd, yyyy")}
                </p>
              </div>
            </div>
          </div>

          <div className="mt-8 p-4 bg-muted/50 rounded-2xl border border-border flex items-start gap-4">
            <div className="w-8 h-8 bg-primary/10 rounded-xl flex items-center justify-center shrink-0">
              <AlertCircle className="w-4 h-4 text-primary" />
            </div>
            <div>
              <p className="text-sm font-bold text-foreground">Pattern Import Rules</p>
              <p className="text-sm text-muted-foreground font-medium mt-1 leading-relaxed">
                This will copy shift types from the source week to the target week.
                Work descriptions will be cleared and existing shifts will be overwritten.
              </p>
            </div>
          </div>

          {importWeekMutation.isError && (
            <div className="mt-5 p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">
                {getApiErrorMessage(importWeekMutation.error)}
              </p>
            </div>
          )}

          <style>{`
            .import-calendar-mini .fc {
              --fc-border-color: transparent;
              --fc-today-bg-color: var(--color-muted);
              font-size: 0.72rem;
              background: transparent;
            }
            .import-calendar-mini .fc .fc-toolbar {
              margin-bottom: 0.5rem !important;
              padding: 0 0.25rem;
            }
            .import-calendar-mini .fc .fc-toolbar-title {
              font-size: 0.8rem;
              font-weight: 700;
              color: var(--color-foreground);
              text-transform: uppercase;
              letter-spacing: 0.04em;
            }
            .import-calendar-mini .fc .fc-button {
              padding: 2px 6px;
              background: var(--color-card);
              border: 1px solid var(--color-border);
              color: var(--color-muted-foreground);
              border-radius: 8px;
              font-weight: 600;
            }
            .import-calendar-mini .fc .fc-button:hover {
              background: var(--color-muted);
              color: var(--color-foreground);
              border-color: var(--color-border);
            }
            .import-calendar-mini .fc .fc-daygrid-day-number {
              padding: 3px 5px;
              font-weight: 700;
              color: var(--color-foreground);
              font-size: 11px;
              text-decoration: none !important;
            }
            .import-calendar-mini .fc-theme-standard td,
            .import-calendar-mini .fc-theme-standard th {
              border: none;
            }
            .import-calendar-mini .fc-daygrid-day.fc-day-today {
              background-color: transparent !important;
            }
            .import-calendar-mini .fc-daygrid-day.fc-day-today .fc-daygrid-day-number {
              color: var(--color-primary);
              font-weight: 800;
            }
            .import-calendar-mini .fc .fc-bg-event {
              opacity: 0.15;
              border-radius: 6px;
            }
            .import-calendar-mini .fc-day-other {
              opacity: 0.25;
            }
            .import-calendar-mini .fc-daygrid-day:hover {
              cursor: pointer;
              background-color: var(--color-muted) !important;
              border-radius: 6px;
            }
            .import-calendar-mini .fc-daygrid-day.invalid-target-day {
              opacity: 0.25 !important;
              pointer-events: none;
            }
            .import-calendar-mini .fc-daygrid-day.valid-target-day {
              opacity: 1 !important;
              background-color: color-mix(in oklab, var(--color-primary) 12%, var(--color-card)) !important;
              cursor: pointer !important;
              border-radius: 4px;
            }
            .import-calendar-mini .fc-daygrid-day.valid-target-day:hover {
              background-color: color-mix(in oklab, var(--color-primary) 20%, var(--color-card)) !important;
            }
            .import-calendar-mini .fc-col-header-cell-cushion {
              font-size: 10px;
              font-weight: 700;
              color: var(--color-muted-foreground);
              text-transform: uppercase;
              letter-spacing: 0.06em;
              text-decoration: none !important;
            }
          `}</style>
        </div>
      </HarmonyDialog>

      {/* ── CLEAR MONTH ── */}
      <HarmonyDialog
        open={isClearModalOpen}
        onOpenChange={setIsClearModalOpen}
        title="Clear Month"
        description={
          schedule
            ? format(new Date(schedule.year, schedule.month - 1, 1), "MMMM yyyy")
            : ""
        }
        size="md"
        onSubmit={handleClearSchedule}
        submitLabel="Clear Month"
        isSubmitting={clearMutation.isPending}
      >
        <div className="space-y-4">
          <p className="text-foreground text-sm font-medium leading-relaxed">
            This will reset{" "}
            <span className="font-bold text-foreground">all days</span> in{" "}
            {schedule
              ? format(new Date(schedule.year, schedule.month - 1, 1), "MMMM yyyy")
              : "this month"}{" "}
            back to default — weekdays become Work Days, weekends become Weekend Days. All shift
            types and work descriptions will be cleared.
          </p>
          <div className="p-4 bg-rose-50 border border-rose-200/80 rounded-2xl flex items-start gap-3">
            <div className="w-6 h-6 bg-rose-100 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
              <AlertTriangle className="w-3.5 h-3.5 text-rose-500" />
            </div>
            <p className="text-rose-800 text-sm font-semibold">This action cannot be undone.</p>
          </div>
          {clearMutation.isError && (
            <div className="p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">
                {getApiErrorMessage(clearMutation.error)}
              </p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* ── LEAVE MODAL ── */}
      <HarmonyDialog
        open={isLeaveModalOpen}
        onOpenChange={(open) => {
          if (!open) {
            setIsLeaveModalOpen(false);
            setSelectedLeaveDate(null);
          }
        }}
        title="Time Off Request"
        description={
          selectedLeaveDate
            ? format(parseISO(selectedLeaveDate), "EEEE, dd MMMM yyyy")
            : ""
        }
        size="2xl"
        onSubmit={() => {
          leaveFormRef.current = document.getElementById("my-schedule-leave-form") as HTMLFormElement | null;
          leaveFormRef.current?.requestSubmit();
        }}
        submitLabel="Submit Request"
        isSubmitting={leaveMutation.isPending}
      >
        <div>
          <HarmonyForm
            id="my-schedule-leave-form"
            schema={leaveFormSchema}
            onSubmit={handleLeaveSubmit}
            hideSubmitButton={true}
            defaultValues={{ leaveType: "0", leaveSize: "0", reason: "" }}
            isPending={leaveMutation.isPending}
          />
          {leaveMutation.isError && (
            <div className="mt-4 p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-3">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">
                {getApiErrorMessage(leaveMutation.error)}
              </p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* ── EXTRA SHIFT MODAL ── */}
      <HarmonyDialog
        open={isExtraShiftModalOpen}
        onOpenChange={(open) => {
          if (!open) {
            setIsExtraShiftModalOpen(false);
            setSelectedExtraShiftDate(null);
            setExtraShiftReason("");
          }
        }}
        title="Add Extra Shift"
        description={
          selectedExtraShiftDate
            ? format(parseISO(selectedExtraShiftDate), "EEEE, dd MMMM yyyy")
            : ""
        }
        size="md"
        onSubmit={handleExtraShiftSubmit}
        submitLabel="Add Shift"
        isSubmitting={isExtraShiftSubmitting}
        submitDisabled={!extraShiftReason.trim()}
      >
        <div className="space-y-6">
          <div className="p-4 bg-primary/5 border border-primary/20 rounded-2xl flex items-start gap-3">
            <div className="w-6 h-6 bg-primary/20 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
              <AlertCircle className="w-3.5 h-3.5 text-primary" />
            </div>
            <p className="text-foreground text-sm font-medium leading-relaxed">
              Adding an extra shift will credit{" "}
              <span className="font-bold">1 day</span> to your leave balance as a Comp-Off.
            </p>
          </div>

          <div className="space-y-3">
            <label htmlFor="extra-shift-reason" className="ws-label">
              Reason for Extra Shift <span className="text-rose-500">*</span>
            </label>
            <textarea
              id="extra-shift-reason"
              value={extraShiftReason}
              onChange={(e) => setExtraShiftReason(e.target.value)}
              placeholder="e.g. Server maintenance, Urgent client delivery..."
              rows={4}
              className="w-full px-4 py-3 border border-border rounded-2xl text-sm text-foreground placeholder:text-muted-foreground font-medium focus:outline-none focus:ring-2 focus:ring-primary/30 focus:border-primary transition-all resize-none bg-muted/30"
            />
          </div>

          <div className="space-y-3">
            <label className="ws-label">Shift Type</label>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Morning", value: ShiftType.MorningShift, icon: SunMedium },
                { label: "Afternoon", value: ShiftType.AfternoonShift, icon: Clock },
                { label: "Night", value: ShiftType.NightShift, icon: EyeOff },
              ].map((s) => (
                <button
                  key={s.value}
                  type="button"
                  aria-label={`${s.label} shift`}
                  aria-pressed={extraShiftType === s.value}
                  onClick={() => setExtraShiftType(s.value)}
                  className={`flex flex-col items-center gap-1.5 py-2.5 rounded-xl border text-[11px] font-bold transition-all ${
                    extraShiftType === s.value
                      ? "bg-primary border-primary text-primary-foreground shadow-md"
                      : "bg-card border-border text-muted-foreground hover:bg-muted"
                  }`}
                >
                  <s.icon
                    className={`w-3.5 h-3.5 ${
                      extraShiftType === s.value ? "text-primary-foreground" : "text-muted-foreground"
                    }`}
                  />
                  {s.label}
                </button>
              ))}
            </div>
          </div>

        </div>
      </HarmonyDialog>

      {/* ── CONTEXT MENU ── */}
      {contextMenu && (
        <div
          role="menu"
          aria-label="Schedule context menu"
          className="fixed bg-card border border-border rounded-2xl shadow-xl shadow-black/10 z-100 py-2 min-w-40 overflow-hidden"
          style={{ top: contextMenu.y, left: contextMenu.x, transform: "translate(-50%, -50%)" }}
        >
          <button
            role="menuitem"
            onClick={() => {
              setSelectedLeaveDate(contextMenu.date);
              setIsLeaveModalOpen(true);
              setContextMenu(null);
            }}
            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-semibold text-foreground hover:bg-primary/10 hover:text-primary transition-colors text-left"
          >
            <div className="w-6 h-6 bg-primary/10 rounded-lg flex items-center justify-center shrink-0">
              <Calendar className="w-3.5 h-3.5 text-primary" />
            </div>
            Add Leave
          </button>
          <button
            role="menuitem"
            onClick={() => {
              setSelectedExtraShiftDate(contextMenu.date);
              setIsExtraShiftModalOpen(true);
              setContextMenu(null);
            }}
            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-semibold text-foreground hover:bg-muted transition-colors text-left border-t border-border"
          >
            <div className="w-6 h-6 bg-muted rounded-lg flex items-center justify-center shrink-0">
              <Clock className="w-3.5 h-3.5 text-muted-foreground" />
            </div>
            Add extra Shift
          </button>
        </div>
      )}
    </div>
  );
}
